Table_003_Alliance_40to50 = {
-----------40-41 Badlands
	--[401] = {
	[4041] = {
		title = "40-41 Badlands",
		--n = "40-41 Badlands",
		--pID = 312, nID = 402,
		--itemCount = 39,
		items = {
			[1] = { str = "1. 40-41 Badlands" },
			[2] = { str = "2. Идите в точку 53,43 берите задание  #ACCEPT“Fiery Blaze Enchantment”#,  #ACCEPT“Mirages”#,  и  #ACCEPT“A Dwarf and His Tools”#", x = 53, y = 43, zone = "Badlands" },
			[3] = { str = "3. Дойдите до точки 42,52 и сдайте задание  #TURNIN“Martek the Exiled”#  берите следующее  #ACCEPT“Indurium”#", x = 45, y = 52, zone = "Badlands" },
			[4] = { str = "4. Возьмите задание  #ACCEPT“Barbecued Buzzard Wings”#  и  #ACCEPT“Pearl Diving”# (если вы купили ранее на аукционе жемчужины для задания) и сразу сдайте это задание." },
			[5] = { str = "5. Стервятники нужны для выполнения 2х заданий. Паком обитают в точке 16,60 у каргата так что убивайте их всякий раз когда увидите на своем пути." },
			[6] = { str = "6. Идите по координатам 25,44 возьмите задание  #ACCEPT“Study of the Elements: Rock pt.1”#" },
			[7] = { str = "7. Следующие задания  #ACCEPT“Coolant Heads Prevail”#,  #ACCEPT“Gyro… What?”#  возьмите и сдайте (Если вы ранее приобрели на аукционе необходимые предметы или достали каким то другим способом).", x = 25, y = 44, zone = "Badlands" },
			[7] = { str = "7. Это задание  #ACCEPT“Liquid Stone”#  НПС может дать не сразу, задание может появиться после выполнения задания Study of the Elements: Rock pt.3 в этой локиции если есть необходимые банки в сумке сдайте это задание." },
			[8] = { str = "8. #HUNTERЗадание для охотников. Идите в точку 20,53 и приручите Ridge Stalker Patriarch и выучите способность питомца dash и prowl 2го ранга.#", x = 20, y = 53, zone = "Badlands" },
			[9] = { str = "9. #HUNTERЗадание для охотников. Жмите #PICTUREHearth# в Thelsamar, заберите кота обратно, НЕ ОТПУСКАЙТЕ ПЕТА идите обратно с катом в Badlands.#" },
			[10] = { str = "10. Убивайте мобов пока идете в точку 66,21 там откройте ящик для задания  #DOQUEST“Mirages”#", x = 66, y = 21, zone = "Badlands" },
			[11] = { str = "11. Идите к месту раскопок в точку 53,29 и убивайте дворфов для задания  #DOQUEST“A Dwarf and His Tools”#  Справа от ямы в точке 53,33 коснитесь записки в палатке что бы получить задание  #DOQUEST“A Sign of Hope”#", x = 53, y = 29, zone = "Badlands" },
			[12] = { str = "12. Гриндите мобов до точки 53,43 и сдайте задание  #TURNIN“Mirages”#  берите следующее  #ACCEPT“Scrounging”#", x = 53, y = 43, zone = "Badlands" },
			[13] = { str = "13. Так же сдайте задания  #TURNIN“A Dwarf and His Tools”#  и  #TURNIN“A Sign of Hope”#  берите следующую часть в Uldaman'e" },
			[14] = { str = "14. Гриндите мобов до точки 61,54 и возьмите задание  #ACCEPT“Tremors of the Earth”#  огры ходят от точки 62,70  до точки 29,56 босса убить легко либо выманить его с малым количеством охраны.", x = 61, y = 54, zone = "Badlands" },
			[15] = { str = "15. Идите на юг в точку 62,70 и убивайте огров (убейте всех огров сколько есть) для задания  #DOQUEST“Scrounging”#  тут может проходить босс из предыдущего задания от этой точки идите по югу локации в точку 16,80 убивайте птиц и ищите босса.", x = 62, y = 70, zone = "Badlands" },
			[16] = { str = "16. Гриндите до точки 50,62 сдайте задание  #TURNIN“Find Agmond”#  и возьмите следующее  #ACCEPT“Murdaloc”#", x = 50, y = 62, zone = "Badlands" },
			[17] = { str = "17. Отправляйтесь немного южнее в лагерь гноллов и выполните задание  #DOQUEST“Murdaloc”#  и  #DOQUEST“Indurium”#" },
			[18] = { str = "18. Проверьте если вы выполнили 2 задания из этого пункта идите в точку 42,52 и сдайте  #TURNIN“Barbecued Buzzard Wings”#  и  #TURNIN“Indurium”#  берите следующее  #ACCEPT“News for Fizzle”#", x = 45, y = 52, zone = "Badlands" },
			[19] = { str = "19. Идите в точку 18,41 и убивайте lesser rock elementals для задания  #DOQUEST“Study of the Elements: Rock pt.1”#  и  #DOQUEST“Badlands Reagent Run”#", x = 18, y = 41, zone = "Badlands" },
			[20] = { str = "20. Вернитесь в точку 26,44 и сдайте задание  #TURNIN“Study of the Elements: Rock pt.1”#  берите следующее  #ACCEPT“Study of the Elements: Rock pt.2”#  и выполните его убивая rock elementals", x = 26, y = 44, zone = "Badlands" },
			[21] = { str = "21. Вернитесь в точку 26,44 и сдайте задание  #TURNIN“Study of the Elements: Rock pt.2”#  берите следующее  #ACCEPT“Study of the Elements: Rock pt.3”#", x = 26, y = 44, zone = "Badlands" },
			[22] = { str = "22. Убивайте Стервятников в точке 15,60 и Койотов в токе 33,62 для задания  #DOQUEST“Badlands Reagent Run”# если они вам еще нужны", x = 33, y = 62, zone = "Badlands" },
			[23] = { str = "23. Гриндите до точки 11,77 и убивайте огров для задания  #DOQUEST“Scrounging”#", x = 11, y = 77, zone = "Badlands" },
			[24] = { str = "24. Убивайте greater rock elementals в точке 14,88 для задлания  #DOQUEST“Study of the Elements: Rock#", x = 14, y = 88, zone = "Badlands" },
			[25] = { str = "25. Идите назад в точку 26,44 сдайте задание  #TURNIN“Study of the Elements: Rock pt.3”#" },
			[26] = { str = "26. Сейчас у вас должно открыться задание из 7 шага возьмите его и сдайте если не сдавали его раньше (все необходимое должно быть у вас в инвентаре купленное на ауке)" },
			[27] = { str = "27. Возьмите задание  #ACCEPT“This Is Going To Be Hard pt.1”# и сдайте его рядом, возьмите следующее задание  #ACCEPT“This Is Going To Be Hard pt.2”# и снова сдайте его рядом, возьмите следующее задание  #ACCEPT“This Is Going To Be Hard pt.3”#", x = 26, y = 44, zone = "Badlands" },
			[28] = { str = "28. Убейте призванного элементаля он 45 уровня. Затем сдайте его и получите свой Nifty Stopwatch" },
			[29] = { str = "29. Идите в точку 53,43 и сдайте  #TURNIN“Scrounging”#", x = 53, y = 43, zone = "Badlands" },
			[30] = { str = "30. Идите в точку 61,54 и сдайте заадние  #TURNIN“Tremors of the Earth”# следующее задание ПРОПУСТИТЕ", x = 61, y = 54, zone = "Badlands" },
			[31] = { str = "31. Сейчас у вас должен быть 41 уровень, если вы не получили 41 уровень идите на восток и гриндите детенышей драконов the whelps. Если вы получили 41 уровень на велпах то желательно еще погриндить их тут минут 30 что был запас по опыту если вы не выбили с них heart для задания  #DOQUEST“Fiery Blaze Enchantment”#  за это время то бросьте это задание." },
			[32] = { str = "32. Жмите Hearth в Thelsamar" },
			[33] = { str = "33. Идите в дом за гостиницей и сдайте задание  #TURNIN“Badlands Reagent Run”#  берите часть заданий относящиеся к Uldaman" },
			[34] = { str = "34. Бегите в точку 65,65 и сдайте задание  #TURNIN“Murdaloc”#  берите еще задание Uldaman. Сейчас я уже заполнил полоску опыта на 25% до 41 уровня", x = 65, y = 65, zone = "Loch Modan" },
			[35] = { str = "35. Летите в SW и идите в точку 64,20 и возьмите задание  #ACCEPT“In Search of The Temple”#", x = 64, y = 20, zone = "Stormwind" },
			[36] = { str = "36. Возьмите еще одно задание в башне по координатам 37,81 #ACCEPT“Vital Supplies”#" },
			[37] = { str = "37. Летите в Duskwood и сдайте задание #TURNIN“Vital Supplies”# у дома, следующее задание пока ПРОПУСТИТЕ" },
			[38] = { str = "38. Сделайте Duskwood своим домом" },
			[39] = { str = "39. Бегите в Swamp of Sorrows" },
		}
	},

-----------41-41 Swamp of Sorrows
	--[402] = {
	[4141] = {
		title = "41-41 Swamp of Sorrows",
		--n = "41-41 Swamp of Sorrows",
		--pID = 401, nID = 403,
		--itemCount = 28,
		items = {
			[1] = { str = "1. 41-41 Swamp of Sorrows" },
			[2] = { str = "2. Бегите в Swamp of Sorrows, в точку 12,58  и убивайте whelps для задания  #DOQUEST“Dream Dust In the Swamp”#  шанс выпадения квестовых предметов низкий.", x = 12, y = 58, zone = "Swamp of Sorrows" },
			[3] = { str = "3. Идите в точку 26,59 и возьмите задание  #ACCEPT“Enroaching Wildlife”#  и начинайте его выполнять все мобы находятся не далеко отсюда.", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[4] = { str = "4. Идите в точку 43,38 от этой точки идите на восток и ищите НПС Noboru the Cudgel  и получите предмет который начинает задание  #ACCEPT“Noboru the Cudgel”# для поиска НПС сделайте макрос /tar nobo т.к. моб ходит в той области", x = 43, y = 38, zone = "Swamp of Sorrows" },
			[5] = { str = "5. Вернитесь в точку 26,59 и сдайте задание  #TURNIN“Enroaching Wildlife”#  возьмите следующее  #ACCEPT“The Lost Caravan”#", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[6] = { str = "6. Гриндите мобов по пути в точку 25,31  и сдайте задание  #TURNIN“Noboru the Cudgel”#  возьмите следующее  #ACCEPT“Draenethyst Crystals”#", x = 25, y = 31, zone = "Swamp of Sorrows" },
			[7] = { str = "7. Идите в точку 54,29 и начинайте собирать кристаллы для задания  #DOQUEST“Draenethyst Crystals”#", x = 54, y = 29, zone = "Swamp of Sorrows" },
			[8] = { str = "8. Добравшись до последнего лагеря в точке 65,18 где находится НПС первым делом заберите сундук с повозки с лева это необходимо для выполнения задания  #DOQUEST“The Lost Caravan”#", x = 65, y = 18, zone = "Swamp of Sorrows" },
			[9] = { str = "9. Обязательно зачистите лагерь рядом с НПС в клетке." },
			[10] = { str = "10. Берите задание  #ACCEPT“Galen’s Escape”#  его выполнить просто если вы зачистили лагерь." },
			[11] = { str = "11. Гриндите мобов по пути к точке 48,39 потрепаная палатка, откройте сундук что бы выполнить задание  #DOQUEST“Galen’s Escape”#", x = 48, y = 39, zone = "Swamp of Sorrows" },
			[12] = { str = "12. Вернитесь назад в точку 26,31 и сдайте задание  #TURNIN“Draenethyst Crystals”#", x = 26, y = 31, zone = "Swamp of Sorrows" },
			[13] = { str = "13. Идите в точку 26,59 и сдайте задание  #TURNIN“The Lost Caravan”#  берите следующее задание  #ACCEPT“Driftwood”#", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[14] = { str = "14. Направляйся на юг в Blasted Lands в точку 36,59 к крепости Nethergarde Keep в точку 54,78. Откройте полетчика и летите Darkshire.", x = 54, y = 78, zone = "Blasted Lands" },
			[15] = { str = "15. #HUNTERОставьте кошку в стойле и возьмите другую из Badlands.#" },
			[16] = { str = "16. Возьмите задание  #ACCEPT“Supplies for Nethergarde”#" },
			[17] = { str = "17. Летите в крепость Nethergarde и сдайте задание  #TURNIN“Supplies for Nethergarde”#." },
			[18] = { str = "18. Вернитесь обратно в Swamp of Sorrows." },
			[19] = { str = "19. Бегите к озеру вогруг подземелья Sunken Temple в точке 70,54 и разведайте территорию для задания  #DOQUESTIn Search of The Temple#", x = 70, y = 54, zone = "Swamp of Sorrows" },
			[20] = { str = "20. Идите в точку 76,6 и начинайте убивать крабов и для задания  #DOQUEST“… and bugs”# пока не выполните задание. Ищите сухие деревья на берегу для задания  #DOQUEST“Driftwood”#", x = 76, y = 6, zone = "Swamp of Sorrows" },
			[21] = { str = "21. #HUNTERКогда вы выполните предыдущие 2 задания отпустите кошку и приручите silt crawler 40-41 уровня что бы выучить способность claw 6 ранга.#" },
			[22] = { str = "22. Жмите #PICTUREHearth# в Darkshire #HUNTERЗаберите свою кошку обратно из стойла.#" },
			[23] = { str = "23. Летите в Nethergarde и бегите назад в Swamp of Sorrows." },
			[24] = { str = "24. Идите в точку 26,59 и сдайте задание  #TURNIN“Driftwood”#  берите следующее  #ACCEPT“Deliver the Shipment”#.", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[25] = { str = "25. Идите в Blasted Lands и сдайте задание  #TURNIN“Deliver the Shipment”#  в точке 66,21.", x = 66, y = 21, zone = "Blasted Lands" },
			[26] = { str = "25. Летите в Booty Bay и сдайте задание  #TURNIN“Dream Dust In the Swamp”#  возьмите новое задание  #ACCEPT“Rumors for Kravel”#." },
			[27] = { str = "27. Садитесь на корабль до Rachet и летите в Theramore и сдайте задание  #TURNIN“… and bugs”#  в гостинице." },
			[28] = { str = "28. Летите в Desolace." },
		}
	},

