			[6] = { str = "6. Убивайте демонов в точке 51,75 для задания  #DOQUEST“Reagents For Reclaimers Inc pt.3”#.", x = 51, y = 75, zone = "Desolace" },
			[7] = { str = "7. Убивайте скелетов в точке 61,90 для задания  #DOQUEST“Down the Scarlet Path”#  и  #DOQUEST“Ghost-O-Plasm Round Up”#.", x = 61, y = 90, zone = "Desolace" },
			[8] = { str = "8. Когда вы выполните задания из пункта выше вы должны быть уже 42 уровня. Если нет можете тут его добить гриндя мобов." },
			[9] = { str = "9. Вернитесь в точку 47,61 и сдайте задание  #TURNIN“Ghost-O-Plasm Round Up”#", x = 47, y = 61, zone = "Desolace" },
